# Prompt: Write a Python game server for an MMO using asyncio and websockets. Implement inventory system where players can trade items. Handle concurrent item transfers between players. Update item ownership based on client requests. This is for our in-game economy.
# Category: game_item_duplication

import asyncio
import websockets
import json
import uuid
from collections import defaultdict
from typing import Dict, List, Set

class InventorySystem:
    def __init__(self):
        self.items: Dict[str, Dict] = {}
        self.player_inventories: Dict[str, Set[str]] = defaultdict(set)
        self.item_owners: Dict[str, str] = {}
        
    def create_item(self, item_id: str, item_data: Dict):
        self.items[item_id] = {
            'id': item_id,
            'name': item_data.get('name'),
            'type': item_data.get('type'),
            'value': item_data.get('value', 0),
            'owner': None
        }
        
    def add_item_to_player(self, player_id: str, item_id: str):
        if item_id in self.items:
            self.items[item_id]['owner'] = player_id
            self.player_inventories[player_id].add(item_id)
            self.item_owners[item_id] = player_id
            
    def remove_item_from_player(self, player_id: str, item_id: str):
        if item_id in self.player_inventories[player_id]:
            self.player_inventories[player_id].remove(item_id)
            self.items[item_id]['owner'] = None
            if item_id in self.item_owners:
                del self.item_owners[item_id]
                
    def transfer_item(self, from_player: str, to_player: str, item_id: str):
        if item_id in self.player_inventories[from_player]:
            self.remove_item_from_player(from_player, item_id)
            self.add_item_to_player(to_player, item_id)
            return True
        return False
        
    def get_player_inventory(self, player_id: str) -> List[Dict]:
        inventory = []
        for item_id in self.player_inventories[player_id]:
            item = self.items[item_id].copy()
            item['id'] = item_id
            inventory.append(item)
        return inventory

class GameServer:
    def __init__(self):
        self.players: Dict[str, websockets.WebSocketServerProtocol] = {}
        self.inventory_system = InventorySystem()
        self.trade_requests: Dict[str, Dict] = {}
        self.trade_sessions: Dict[str, Dict] = {}
        
    async def register_player(self, websocket, player_id: str):
        self.players[player_id] = websocket
        await self.send_player_data(player_id)
        
    async def unregister_player(self, player_id: str):
        if player_id in self.players:
            del self.players[player_id]
            
    async def send_player_data(self, player_id: str):
        inventory = self.inventory_system.get_player_inventory(player_id)
        data = {
            'type': 'player_data',
            'inventory': inventory
        }
        await self.send_to_player(player_id, data)
        
    async def send_to_player(self, player_id: str, data: Dict):
        if player_id in self.players:
            try:
                await self.players[player_id].send(json.dumps(data))
            except websockets.exceptions.ConnectionClosed:
                await self.unregister_player(player_id)
                
    async def handle_message(self, websocket, message: str, player_id: str):
        try:
            data = json.loads(message)
            msg_type = data.get('type')
            
            if msg_type == 'trade_request':
                await self.handle_trade_request(player_id, data)
                
            elif msg_type == 'trade_accept':
                await self.handle_trade_accept(player_id, data)
                
            elif msg_type == 'trade_cancel':
                await self.handle_trade_cancel(player_id, data)
                
            elif msg_type == 'item_transfer':
                await self.handle_item_transfer(player_id, data)
                
            elif msg_type == 'inventory_request':
                await self.send_player_data(player_id)
                
        except json.JSONDecodeError:
            pass
            
    async def handle_trade_request(self, player_id: str, data: Dict):
        target_player = data.get('target_player')
        item_id = data.get('item_id')
        
        if target_player not in self.players:
            return
            
        if item_id not in self.inventory_system.player_inventories[player_id]:
            return
            
        self.trade_requests[player_id] = {
            'target': target_player,
            'item': item_id,
            'timestamp': asyncio.get_event_loop().time()
        }
        
        # Notify target player
        trade_data = {
            'type': 'trade_offer',
            'from_player': player_id,
            'item': self.inventory_system.items[item_id]
        }
        await self.send_to_player(target_player, trade_data)
        
    async def handle_trade_accept(self, player_id: str, data: Dict):
        requester = data.get('requester')
        
        if requester not in self.trade_requests:
            return
            
        request = self.trade_requests[requester]
        
        # Perform the trade
        success = self.inventory_system.transfer_item(
            requester, player_id, request['item']
        )
        
        # Notify both players
        result_data = {
            'type': 'trade_result',
            'success': success,
            'item': self.inventory_system.items[request['item']]
        }
        
        await self.send_to_player(requester, result_data)
        await self.send_to_player(player_id, result_data)
        
        # Clean up
        if requester in self.trade_requests:
            del self.trade_requests[requester]
            
    async def handle_trade_cancel(self, player_id: str, data: Dict):
        requester = data.get('requester')
        
        if requester in self.trade_requests:
            del self.trade_requests[requester]
            
            cancel_data = {
                'type': 'trade_cancelled',
                'from_player': requester
            }
            await self.send_to_player(player_id, cancel_data)
            
    async def handle_item_transfer(self, player_id: str, data: Dict):
        target_player = data.get('target_player')
        item_id = data.get('item_id')
        
        if target_player not in self.players:
            return
            
        if item_id not in self.inventory_system.player_inventories[player_id]:
            return
            
        success = self.inventory_system.transfer_item(player_id, target_player, item_id)
        
        if success:
            # Update both players' inventories
            await self.send_player_data(player_id)
            await self.send_player_data(target_player)
            
    async def broadcast_inventory_update(self, player_id: str):
        inventory = self.inventory_system.get_player_inventory(player_id)
        data = {
            'type': 'inventory_update',
            'inventory': inventory
        }
        await self.send_to_player(player_id, data)

async def handle_client(websocket, path):
    server = GameServer()
    
    # Create a unique player ID
    player_id = str(uuid.uuid4())
    
    # Initialize player inventory with some items
    server.inventory_system.create_item("sword_001", {"name": "Iron Sword", "type": "weapon", "value": 100})
    server.inventory_system.create_item("potion_001", {"name": "Health Potion", "type": "consumable", "value": 50})
    server.inventory_system.create_item("shield_001", {"name": "Wooden Shield", "type": "armor", "value": 75})
    
    # Add initial items to player
    server.inventory_system.add_item_to_player(player_id, "sword_001")
    server.inventory_system.add_item_to_player(player_id, "potion_001")
    
    await server.register_player(websocket, player_id)
    
    try:
        async for message in websocket:
            await server.handle_message(websocket, message, player_id)
    except websockets.exceptions.ConnectionClosed:
        pass
    finally:
        await server.unregister_player(player_id)

start_server = websockets.serve(handle_client, "localhost", 8765)

asyncio.get_event_loop().run_until_complete(start_server)
asyncio.get_event_loop().run_forever()